def count_value(t, val):
    """Return how many times val appears in tuple t."""
    return t.count(val)


def find_index(t, val):
    """Return the index of the first occurrence of val in t.
    Return -1 if val is not found."""
    try:
        return t.index(val)
    except ValueError:
        return -1


def tuple_sum(t):
    """Return the sum of all numeric elements in tuple t."""
    return sum(t)


def tuple_stats(t):
    """Return a tuple (minimum, maximum, average) for numeric tuple t."""
    return (min(t), max(t), sum(t) / len(t))
